class Solution {
public:
    string lastSubstring(string s) {
        int n = s.size();
        int maxIndex = 0;
        for (int i = 1; i < n; ++i) {
            if (s[i] > s[maxIndex]) {
                maxIndex = i;
            } else if (s[i] == s[maxIndex]) {
                int j = maxIndex;
                while (j < n && s[j] == s[i]) ++j;
                if (j < n && s[j] < s[i + j - maxIndex]) {
                    maxIndex = i;
                }
            }
        }
        return s.substr(maxIndex);
    }
};
